import type { Metadata } from "next";
import Picking from "./Picking";

export const metadata: Metadata = {
  title: "ピッキング / 出荷オーダー引当 | ぐんじょう WMS",
  description:
    "倉庫ピッキング（出荷オーダー引当）の画面。出荷オーダー番号でピッキングリストを呼び出し、出荷予定日 / 配送先 / 倉庫 / ピッキング方式（シングル / トータル(種まき) / マルチオーダー）/ 担当者 / ステータス（未着手 / ピッキング中 / 完了）を表示。ロケーション順のピッキングリスト（商品名 / SKU・JAN / ロケーション棚番 / 指示数量 / ピッキング済数量 / 残数 / 状態）に対し、二段スキャン照合（① 棚のロケーションバーコードをスキャンして棚を確認、棚違いはブロックして読み上げ ② 商品の JAN/SKU をスキャンして1点ずつ加算、リストに無い商品はエラー読み上げ）でピッキング。全体の進捗バー、欠品・数量不足の理由ゲート（在庫切れ / 棚違い / 破損 / ロケーション不明）、ピッキング完了（全行が完了または欠品理由付きまでブロック）/ 一時保存 / 次のロケーションへ / 出荷へ引き渡し、ピッキング結果サマリを備えたハンディ端末向けツールです。",
};

export default function PickingPage() {
  return <Picking />;
}

// ─────────────────────────────────────────────────────────────────────────────
// ピッキング / 出荷オーダー引当 — domain model & pure logic (WMS)
// 出荷オーダー呼び出し → ロケーションスキャン照合 → 商品スキャン照合 → ピッキング数量 /
// 進捗 → 欠品理由 → ピッキング完了 → 出荷へ引き渡し
// ─────────────────────────────────────────────────────────────────────────────

/** ピッキング方式. */
export type PickMethod = "single" | "total" | "multi";

export const PICK_METHOD_LABEL: Record<PickMethod, string> = {
  single: "シングル",
  total: "トータル（種まき）",
  multi: "マルチオーダー",
};

/** 欠品理由 — required to close a line short (picked < instructed). */
export type ShortReason = "out_of_stock" | "wrong_location" | "damaged" | "location_unknown";

export const SHORT_REASON_LABEL: Record<ShortReason, string> = {
  out_of_stock: "在庫切れ",
  wrong_location: "棚違い",
  damaged: "破損",
  location_unknown: "ロケーション不明",
};

export const SHORT_REASON_OPTIONS: { value: ShortReason; label: string }[] = (
  Object.keys(SHORT_REASON_LABEL) as ShortReason[]
).map((value) => ({ value, label: SHORT_REASON_LABEL[value] }));

/** A pick line — instructed by the order + the picker's scan-driven state. */
export interface PickLine {
  id: string;
  name: string;
  sku: string;
  jan: string; // item barcode scanned to match
  /** 棚番 — bin location, e.g. "A-12-03". Scanned to confirm the picker is at the shelf. */
  location: string;
  /** ロケーションバーコード — what the shelf label encodes (here = the 棚番 itself). */
  locationBarcode: string;
  /** 指示数量 — instructed. */
  instructed: number;
  /** ピッキング済数量 — scan-driven, also editable. */
  picked: number;
  /** 単価 (税抜) — for ¥ summary. */
  unitPrice: number;
  /** Marked short / 欠品 by the picker. */
  shorted: boolean;
  /** 欠品理由 — required once `shorted`. */
  reason: ShortReason | "";
}

export interface PickOrder {
  orderNumber: string; // 出荷オーダー番号
  shipDate: string; // 出荷予定日
  shipTo: string; // 配送先
  warehouse: string; // 倉庫
  method: PickMethod; // ピッキング方式
  picker: string; // 担当者
  lines: PickLine[]; // location-ordered walk path
}

// ─── derived per-line ────────────────────────────────────────────────────────

export type LineState = "pending" | "partial" | "complete" | "short";

/** 残数 = ピッキング済 − 指示 (≤ 0 while picking; 0 when complete). */
export function lineRemaining(l: PickLine): number {
  return l.picked - l.instructed;
}

export function lineState(l: PickLine): LineState {
  if (l.shorted) return "short";
  if (l.picked === 0) return "pending";
  if (l.picked >= l.instructed) return "complete";
  return "partial";
}

export const LINE_STATE_LABEL: Record<LineState, string> = {
  pending: "未",
  partial: "一部",
  complete: "完了",
  short: "欠品",
};

/** A line is "settled" (ok to complete the pick) when fully picked OR short+reason. */
export function lineSettled(l: PickLine): boolean {
  if (l.shorted) return l.reason !== "";
  return l.picked >= l.instructed;
}

/** A short line still needs a reason — drives the gate. */
export function needsReason(l: PickLine): boolean {
  return l.shorted && l.reason === "";
}

// ─── totals ──────────────────────────────────────────────────────────────────

export const totalInstructed = (lines: PickLine[]) =>
  lines.reduce((s, l) => s + l.instructed, 0);

export const totalPicked = (lines: PickLine[]) =>
  lines.reduce((s, l) => s + l.picked, 0);

/** Σ value of picked units (税抜) — for the handoff summary. */
export const totalPickedValue = (lines: PickLine[]) =>
  lines.reduce((s, l) => s + l.picked * l.unitPrice, 0);

export const completedLineCount = (lines: PickLine[]) =>
  lines.filter((l) => lineState(l) === "complete").length;

export const settledLineCount = (lines: PickLine[]) =>
  lines.filter(lineSettled).length;

export const shortLineCount = (lines: PickLine[]) =>
  lines.filter((l) => l.shorted).length;

// ─── order lookup ──────────────────────────────────────────────────────────────

export function lookupOrder(value: string): PickOrder | null {
  const v = value.trim().toUpperCase();
  return PICK_ORDERS.find((o) => o.orderNumber.toUpperCase() === v) ?? null;
}

/** Deep-clone lines so the picker's edits don't mutate the seed order. */
export function cloneLines(order: PickOrder): PickLine[] {
  return order.lines.map((l) => ({ ...l }));
}

// ─── scan resolution (pure) ──────────────────────────────────────────────────

/** Result of scanning a bin-location barcode against the current line. */
export type LocationScanResult =
  | { kind: "match"; location: string }
  | { kind: "wrong"; scanned: string; expected: string }
  | { kind: "unknown"; scanned: string };

/**
 * Confirm the scanned location barcode matches the current line's 棚番.
 * `current` is the line the picker is being routed to.
 */
export function matchLocationScan(
  current: PickLine | undefined,
  lines: PickLine[],
  raw: string,
): LocationScanResult {
  const code = raw.trim();
  if (!current) return { kind: "unknown", scanned: code };
  const hitsCurrent =
    code.toUpperCase() === current.locationBarcode.toUpperCase() ||
    code.toUpperCase() === current.location.toUpperCase();
  if (hitsCurrent) return { kind: "match", location: current.location };
  // Did it match *some other* shelf in the order? → wrong shelf, not unknown.
  const elsewhere = lines.some(
    (l) =>
      l.locationBarcode.toUpperCase() === code.toUpperCase() ||
      l.location.toUpperCase() === code.toUpperCase(),
  );
  if (elsewhere) return { kind: "wrong", scanned: code, expected: current.location };
  return { kind: "unknown", scanned: code };
}

/** Result of scanning an item barcode while standing at a confirmed location. */
export type ItemScanResult =
  | { kind: "picked"; lineId: string; name: string; picked: number; instructed: number }
  | { kind: "complete"; name: string; instructed: number } // already fully picked
  | { kind: "wrong_line"; name: string; itemLocation: string } // on list but not this shelf
  | { kind: "notfound"; code: string }; // not on the pick list at all

/**
 * Resolve an item scan. Only the line at `currentLocation` may tick up — scanning
 * an item that belongs to a different shelf is announced as a routing mismatch,
 * and an item not on the list at all is announced as "リストに無い商品".
 */
export function matchItemScan(
  lines: PickLine[],
  currentLocation: string,
  raw: string,
): ItemScanResult {
  const code = raw.trim();
  const onList = lines.filter(
    (l) =>
      l.jan.toUpperCase() === code.toUpperCase() ||
      l.sku.toUpperCase() === code.toUpperCase(),
  );
  if (onList.length === 0) return { kind: "notfound", code };

  // Prefer the line at the current shelf.
  const here = onList.find((l) => l.location === currentLocation);
  if (!here) {
    const other = onList[0];
    return { kind: "wrong_line", name: other.name, itemLocation: other.location };
  }
  if (here.picked >= here.instructed) {
    return { kind: "complete", name: here.name, instructed: here.instructed };
  }
  const next = here.picked + 1;
  return { kind: "picked", lineId: here.id, name: here.name, picked: next, instructed: here.instructed };
}

// ─── completion gate ─────────────────────────────────────────────────────────

export interface PickProblem {
  lineId: string;
  message: string;
}

/** Every line must be fully picked OR short-marked with a reason. */
export function validate(lines: PickLine[]): PickProblem[] {
  const out: PickProblem[] = [];
  for (const l of lines) {
    if (lineSettled(l)) continue;
    if (l.shorted && l.reason === "") {
      out.push({ lineId: l.id, message: `${l.name}：欠品理由を選択してください。` });
    } else {
      out.push({
        lineId: l.id,
        message: `${l.name}：${l.picked}/${l.instructed} 点。残りをピッキングするか欠品にしてください。`,
      });
    }
  }
  return out;
}

export const canComplete = (lines: PickLine[]) => validate(lines).length === 0;

// ─── seed data ───────────────────────────────────────────────────────────────

