"use client";

import * as React from "react";
import {
  IconBarcode,
  IconScan,
  IconSearch,
  IconBuildingWarehouse,
  IconTruckDelivery,
  IconCalendarEvent,
  IconMapPin,
  IconRoute,
  IconClipboardList,
  IconClipboardCheck,
  IconDeviceFloppy,
  IconAlertTriangle,
  IconCircleCheck,
  IconCircleDot,
  IconArrowRight,
  IconArrowBigRightLines,
  IconUser,
  IconX,
  IconPackageExport,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Delta,
