  ScanInput,
  Select,
  Separator,
  Statistic,
  formatCurrency,
  formatNumber,
  type EditableColumn,
  type BadgeProps,
  type ScanResult,
} from "@gunjo/ui";

import {
  PICK_ORDERS,
  PICK_METHOD_LABEL,
  SHORT_REASON_OPTIONS,
  canComplete,
  cloneLines,
  completedLineCount,
  lineRemaining,
  lineSettled,
  lineState,
  LINE_STATE_LABEL,
  lookupOrder,
  matchItemScan,
  matchLocationScan,
  needsReason,
  settledLineCount,
  shortLineCount,
  totalInstructed,
  totalPicked,
  totalPickedValue,
  validate,
  type LineState,
  type PickLine,
  type PickOrder,
  type ShortReason,
} from "./data";

const yen = (n: number) => formatCurrency(n, { maximumFractionDigits: 0 });

type Phase = "lookup" | "picking" | "done";
/** Two-step scan gate: confirm the shelf, then scan items there. */
type ScanStage = "location" | "item";

interface FeedEvent {
  id: number;
  kind: "ok" | "warn" | "error";
  label: string;
  detail: string;
}

const STATE_BADGE_VARIANT: Record<LineState, BadgeProps["variant"]> = {
  pending: "outline",
  partial: "info",
  complete: "success",
  short: "warning",
};

const STATE_ICON: Record<LineState, React.ReactNode> = {
  pending: <IconCircleDot className="h-3.5 w-3.5" aria-hidden="true" />,
  partial: <IconCircleDot className="h-3.5 w-3.5" aria-hidden="true" />,
  complete: <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />,
  short: <IconAlertTriangle className="h-3.5 w-3.5" aria-hidden="true" />,
};

export default function Picking() {
  const [phase, setPhase] = React.useState<Phase>("lookup");
  const [orderInput, setOrderInput] = React.useState("");
  const [lookupError, setLookupError] = React.useState<string | null>(null);

  const [order, setOrder] = React.useState<PickOrder | null>(null);
  const [lines, setLines] = React.useState<PickLine[]>([]);

  // two-step scan gate state
  const [currentIdx, setCurrentIdx] = React.useState(0);
  const [scanStage, setScanStage] = React.useState<ScanStage>("location");
  const [confirmedLocation, setConfirmedLocation] = React.useState<string | null>(null);
  const [feed, setFeed] = React.useState<FeedEvent[]>([]);
  const feedSeq = React.useRef(0);

  const [showErrors, setShowErrors] = React.useState(false);
  const [summaryOpen, setSummaryOpen] = React.useState(false);
  const [savedAt, setSavedAt] = React.useState<string | null>(null);

  const accepted = phase === "done";
  const current = lines[currentIdx];

  const problems = React.useMemo(() => validate(lines), [lines]);
  const problemByLine = React.useMemo(() => {
    const m = new Map<string, string>();
    for (const p of problems) if (!m.has(p.lineId)) m.set(p.lineId, p.message);
    return m;
  }, [problems]);

  // ─── totals / progress ───────────────────────────────────────────────────────
  const instructed = totalInstructed(lines);
  const picked = totalPicked(lines);
  const completeLines = completedLineCount(lines);
  const settledLines = settledLineCount(lines);
  const shortCount = shortLineCount(lines);
  const pickedValue = totalPickedValue(lines);
  const pct = instructed ? Math.round((picked / instructed) * 100) : 0;

  function pushFeed(e: Omit<FeedEvent, "id">) {
    feedSeq.current += 1;
    const id = feedSeq.current;
    setFeed((prev) => [{ ...e, id }, ...prev].slice(0, 8));
  }

  // ─── order lookup ──────────────────────────────────────────────────────────────
  function resolveOrder(value: string) {
    const found = lookupOrder(value);
    if (!found) {
      setLookupError(
        `「${value}」に一致する出荷オーダーが見つかりません。オーダー番号（例 SO-2026-0488）を確認してください。`,
      );
      return;
    }
    setOrder(found);
    setLines(cloneLines(found));
    setLookupError(null);
    setShowErrors(false);
    setSavedAt(null);
    setCurrentIdx(0);
    setScanStage("location");
    setConfirmedLocation(null);
    setFeed([]);
    setPhase("picking");
  }

  // ─── line mutation ────────────────────────────────────────────────────────────
  const patchLine = React.useCallback((id: string, patch: Partial<PickLine>) => {
    setLines((prev) => prev.map((l) => (l.id === id ? { ...l, ...patch } : l)));
  }, []);

  // ─── advance to the next unsettled location on the walk path ───────────────────
  const goToNext = React.useCallback(() => {
    setLines((prev) => {
      const start = currentIdx;
      for (let step = 1; step <= prev.length; step++) {
        const idx = (start + step) % prev.length;
        if (!lineSettled(prev[idx])) {
          setCurrentIdx(idx);
          setScanStage("location");
          setConfirmedLocation(null);
          return prev;
        }
      }
      // nothing left unsettled
      setScanStage("location");
      setConfirmedLocation(null);
      return prev;
    });
  }, [currentIdx]);

  // ─── STEP 1: location scan (the gate) ─────────────────────────────────────────
  const handleLocationScan = (code: string): ScanResult => {
    const res = matchLocationScan(current, lines, code);
    if (res.kind === "match") {
      setConfirmedLocation(res.location);
      setScanStage("item");
      pushFeed({ kind: "ok", label: `ロケーション ${res.location}`, detail: "棚を確認" });
      return { ok: true, message: `ロケーション ${res.location} を確認しました。商品をスキャンしてください。` };
    }
    if (res.kind === "wrong") {
      pushFeed({ kind: "warn", label: res.scanned, detail: `棚違い（正 ${res.expected}）` });
      return {
        ok: false,
        message: `棚が違います。指示は ${res.expected} です（スキャン: ${res.scanned}）。正しい棚へ移動してください。`,
      };
    }
    pushFeed({ kind: "error", label: res.scanned, detail: "未知のロケーション" });
    return {
      ok: false,
      message: `このオーダーにないロケーションです（${res.scanned}）。棚番ラベルを確認してください。`,
    };
  };

  // ─── STEP 2: item scan → increment by exactly 1 ────────────────────────────────
  const handleItemScan = (code: string): ScanResult => {
    if (!confirmedLocation) {
      return { ok: false, message: "先にロケーションをスキャンして棚を確認してください。" };
    }
    const res = matchItemScan(lines, confirmedLocation, code);
    if (res.kind === "picked") {
      patchLine(res.lineId, { picked: res.picked });
      pushFeed({ kind: "ok", label: res.name, detail: `${res.picked} / ${res.instructed} 点` });
      return {
        ok: true,
        message: `${res.name} を1点ピッキング（${res.picked} / ${res.instructed} 点）。`,
      };
    }
    if (res.kind === "complete") {
      pushFeed({ kind: "warn", label: res.name, detail: "指示数に到達済み" });
      return {
        ok: false,
        message: `${res.name} は指示数 ${res.instructed} 点に達しています。これ以上は加算しません。`,
      };
    }
    if (res.kind === "wrong_line") {
      pushFeed({ kind: "warn", label: res.name, detail: `別の棚 ${res.itemLocation}` });
      return {
        ok: false,
        message: `${res.name} はこの棚の対象ではありません（ロケーション ${res.itemLocation}）。`,
      };
    }
    pushFeed({ kind: "error", label: res.code, detail: "リストに無い商品" });
    return {
      ok: false,
      message: `リストに無い商品です（コード ${res.code}）。ピッキングリストを確認してください。`,
    };
  };

  // ─── short-pick toggle ─────────────────────────────────────────────────────────
  function toggleShort(id: string, next: boolean) {
    patchLine(id, next ? { shorted: true } : { shorted: false, reason: "" });
  }

  // ─── complete ──────────────────────────────────────────────────────────────────
  function attemptComplete() {
    if (!canComplete(lines)) {
      setShowErrors(true);
      return;
    }
    setShowErrors(false);
    setPhase("done");
    setSummaryOpen(false);
  }

  function reset() {
    setPhase("lookup");
    setOrder(null);
    setLines([]);
    setOrderInput("");
    setCurrentIdx(0);
    setScanStage("location");
    setConfirmedLocation(null);
    setFeed([]);
    setShowErrors(false);
    setSavedAt(null);
  }

  // ─── pick-lines grid columns ───────────────────────────────────────────────────
  const columns: EditableColumn<PickLine>[] = [
    {
      id: "location",
      header: "ロケーション",
      width: "7.5rem",
      minWidth: "6.5rem",
      cell: (row) => {
        const isCurrent = current?.id === row.id && !accepted;
        return (
          <div className="flex items-center gap-1.5">
            <IconMapPin
              className={isCurrent ? "h-4 w-4 shrink-0 text-primary" : "h-4 w-4 shrink-0 text-muted-foreground"}
              aria-hidden="true"
            />
            <span className="font-mono text-sm font-medium tabular-nums">{row.location}</span>
            {isCurrent ? <span className="sr-only">（現在のロケーション）</span> : null}
          </div>
        );
      },
    },
    {
      id: "name",
      header: "商品 / SKU・JAN",
      minWidth: "13rem",
      cell: (row) => (
        <div className="flex flex-col">
          <span className="font-medium leading-snug">{row.name}</span>
          <span className="font-mono text-xs text-muted-foreground tabular-nums">
            {row.sku} · {row.jan}
          </span>
        </div>
      ),
    },
    {
      id: "instructed",
      header: "指示数量",
      align: "center",
      width: "5.5rem",
      cell: (row) => <span className="tabular-nums">{formatNumber(row.instructed)}</span>,
    },
    {
      id: "picked",
      header: "ピッキング済",
      align: "center",
      width: "9rem",
      minWidth: "8.5rem",
      cell: (row, ctx) => (
        <NumberInput
          layout="stepper"
          value={row.picked}
          min={0}
          max={row.instructed}
          onValueChange={(n) => patchLine(row.id, { picked: n })}
          aria-label={`${ctx.ariaLabel}（スキャンで加算・手修正可）`}
          disabled={accepted}
        />
      ),
    },
    {
      id: "remaining",
      header: "残数",
      align: "center",
      width: "7rem",
      minWidth: "6rem",
      cell: (row) => {
        if (row.shorted) {
          return <span className="text-xs font-medium text-warning">欠品</span>;
        }
        const rem = lineRemaining(row); // ≤ 0
        // remaining conveyed by sign + text label (残 / 完了), never colour alone.
        return (
          <Delta
            value={rem}
            format={(n) => (n === 0 ? "0" : formatNumber(Math.abs(n)))}
            hideArrow
            labels={{ negative: "残", zero: "完了" }}
            showLabel
            // remaining isn't an error → muted; done → success.
            tones={{ negative: "muted", zero: "success" }}
          />
        );
      },
    },
    {
      id: "state",
      header: "状態",
      align: "center",
      width: "6.5rem",
      cell: (row) => {
        const s = lineState(row);
        return (
          <Badge variant={STATE_BADGE_VARIANT[s]} className="gap-1">
            {STATE_ICON[s]}
            {LINE_STATE_LABEL[s]}
          </Badge>
        );
      },
    },
    {
      id: "short",
      header: "欠品 / 数量不足",
      minWidth: "14rem",
      cell: (row, ctx) => {
        const reasonMissing = needsReason(row);
        return (
          <div className="flex flex-col gap-2">
            <label className="flex items-center gap-2 text-xs font-medium">
              <input
                type="checkbox"
                className="h-4 w-4 rounded border-input accent-[var(--warning)]"
                checked={row.shorted}
                onChange={(e) => toggleShort(row.id, e.target.checked)}
                disabled={accepted}
                aria-label={`${row.name} を欠品にする`}
              />
              欠品にする
            </label>
            {row.shorted ? (
              <Select
                value={row.reason}
                onChange={(e) =>
                  patchLine(row.id, { reason: e.target.value as ShortReason | "" })
                }
                aria-label={`${ctx.ariaLabel}（欠品理由）`}
                aria-invalid={showErrors && reasonMissing ? true : undefined}
                disabled={accepted}
                className="h-8"
              >
                <option value="">欠品理由を選択</option>
                {SHORT_REASON_OPTIONS.map((o) => (
                  <option key={o.value} value={o.value}>
                    {o.label}
                  </option>
                ))}
              </Select>
            ) : (
              <span className="text-xs text-muted-foreground">在庫があれば残りをスキャン</span>
            )}
          </div>
        );
      },
    },
  ];

  function footerCell(col: EditableColumn<PickLine>) {
    if (col.id === "location") return <span className="font-semibold">合計</span>;
    if (col.id === "instructed")
      return <span className="font-semibold tabular-nums">{formatNumber(instructed)}</span>;
    if (col.id === "picked")
      return <span className="font-semibold tabular-nums">{formatNumber(picked)}</span>;
    if (col.id === "state")
      return (
        <span className="text-xs font-medium text-muted-foreground tabular-nums">
          完了 {completeLines}/{lines.length} 行
        </span>
      );
    if (col.id === "short")
      return (
        <span className="text-xs font-medium text-muted-foreground tabular-nums">
          欠品 {shortCount} 件
        </span>
      );
    return null;
  }

  // ─── render ─────────────────────────────────────────────────────────────────
  return (
    <main className="mx-auto flex w-full max-w-6xl flex-col gap-6 p-4 sm:p-6">
      <header className="flex flex-col gap-1">
        <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight">
          <IconPackageExport className="h-6 w-6 shrink-0" aria-hidden="true" />
          ピッキング / 出荷オーダー引当
        </h1>
        <p className="text-sm text-muted-foreground">
          出荷オーダーを呼び出し、ロケーションをスキャンして棚を確認 →
          商品をスキャンしてピッキング数量を加算 — 欠品を処理し、出荷へ引き渡します。
        </p>
      </header>

      {/* ─── order lookup ─── */}
      {phase === "lookup" ? (
        <Card>
          <CardHeader>
            <CardTitle as="h2" className="flex items-center gap-2 text-lg">
              <IconSearch className="h-5 w-5" aria-hidden="true" />
              出荷オーダーの呼び出し
            </CardTitle>
            <CardDescription>
              出荷オーダー番号を入力（またはスキャン）して、ピッキングリストを呼び出します。
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            <form
              className="flex flex-col gap-2 sm:flex-row sm:items-end"
              onSubmit={(e) => {
                e.preventDefault();
                if (orderInput.trim()) resolveOrder(orderInput);
              }}
            >
              <div className="flex w-full flex-col gap-1.5">
                <Label htmlFor="order-lookup">出荷オーダー番号</Label>
                <Input
                  id="order-lookup"
                  value={orderInput}
                  onChange={(e) => setOrderInput(e.target.value)}
                  placeholder="SO-2026-0488"
                  autoComplete="off"
                  aria-invalid={lookupError ? true : undefined}
                  aria-describedby={lookupError ? "order-lookup-error" : undefined}
                />
              </div>
              <Button type="submit" disabled={!orderInput.trim()} className="shrink-0">
                <IconSearch className="h-4 w-4" aria-hidden="true" />
                呼び出す
              </Button>
            </form>

            <div aria-live="assertive">
              {lookupError ? (
                <Alert variant="destructive" id="order-lookup-error">
                  <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                  <AlertTitle as="h3">オーダーが見つかりません</AlertTitle>
                  <AlertDescription>{lookupError}</AlertDescription>
                </Alert>
              ) : null}
            </div>

            <Separator />
            <div className="flex flex-col gap-2">
              <p className="text-xs font-medium text-muted-foreground">本日のピッキング待ち</p>
              <ul className="flex flex-col gap-2">
                {PICK_ORDERS.map((o) => (
                  <li key={o.orderNumber}>
                    <button
                      type="button"
                      onClick={() => {
                        setOrderInput(o.orderNumber);
                        resolveOrder(o.orderNumber);
                      }}
                      className="flex w-full items-center justify-between gap-3 rounded-lg border bg-card p-3 text-left transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                    >
                      <span className="flex flex-col">
                        <span className="font-mono text-sm font-medium">{o.orderNumber}</span>
                        <span className="text-xs text-muted-foreground">
                          {o.shipTo} · {o.lines.length} 行 · {PICK_METHOD_LABEL[o.method]}
                        </span>
                      </span>
                      <Badge variant="outline" className="shrink-0">
                        出荷予定 {o.shipDate}
                      </Badge>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </CardContent>
        </Card>
      ) : null}

      {/* ─── picking / done ─── */}
      {order ? (
        <>
          {/* order header */}
          <Card>
            <CardHeader className="pb-4">
              <div className="flex flex-wrap items-start justify-between gap-3">
                <div className="flex flex-col gap-1">
                  <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                    <IconTruckDelivery className="h-5 w-5" aria-hidden="true" />
                    <span className="font-mono">{order.orderNumber}</span>
                  </CardTitle>
                  <CardDescription>{order.shipTo}</CardDescription>
                </div>
                {accepted ? (
                  <Badge variant="success" className="h-6 gap-1">
                    <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />
                    完了
                  </Badge>
                ) : picked > 0 ? (
                  <Badge variant="info" className="h-6">
                    ピッキング中
                  </Badge>
                ) : (
                  <Badge variant="outline" className="h-6">
                    未着手
                  </Badge>
                )}
              </div>
            </CardHeader>
            <CardContent>
              <dl className="grid grid-cols-2 gap-x-4 gap-y-3 text-sm sm:grid-cols-3 lg:grid-cols-6">
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconCalendarEvent className="h-3.5 w-3.5" aria-hidden="true" />
                    出荷予定日
                  </dt>
                  <dd className="tabular-nums">{order.shipDate}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconBuildingWarehouse className="h-3.5 w-3.5" aria-hidden="true" />
                    倉庫
                  </dt>
                  <dd>{order.warehouse}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">配送先</dt>
                  <dd>{order.shipTo}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">ピッキング方式</dt>
                  <dd>{PICK_METHOD_LABEL[order.method]}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconUser className="h-3.5 w-3.5" aria-hidden="true" />
                    担当者
                  </dt>
                  <dd>{order.picker}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">明細行数</dt>
                  <dd className="tabular-nums">{order.lines.length} 行</dd>
                </div>
              </dl>
            </CardContent>
          </Card>

          {/* progress */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <IconClipboardList className="h-5 w-5" aria-hidden="true" />
                ピッキング進捗
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
                <Statistic
                  label="完了行"
                  value={`${completeLines} / ${lines.length} 行`}
                  hint={`欠品 ${shortCount} 件`}
                />
                <Statistic
                  label="ピッキング点数"
                  value={`${formatNumber(picked)} / ${formatNumber(instructed)} 点`}
                  hint={`達成 ${pct}%`}
                />
                <Statistic
                  label="未処理行"
                  value={`${formatNumber(lines.length - settledLines)} 行`}
                  trend={lines.length - settledLines > 0 ? "down" : "flat"}
                  tone={lines.length - settledLines > 0 ? "negative" : "neutral"}
                  change={lines.length - settledLines > 0 ? "残あり" : "なし"}
                />
                <Statistic label="ピッキング金額" value={yen(pickedValue)} />
              </div>
              <div className="flex flex-col gap-1.5">
                <div className="flex items-center justify-between text-xs font-medium text-muted-foreground">
                  <span>全体の進捗</span>
                  <span className="tabular-nums">
                    {formatNumber(picked)} / {formatNumber(instructed)} 点（{pct}%）
                  </span>
                </div>
                <Progress
                  value={picked}
                  max={instructed || 1}
                  label="ピッキング全体の進捗"
                  valueText={`ピッキング ${picked} / ${instructed} 点（${pct}%）`}
                />
              </div>
            </CardContent>
          </Card>

          {/* two-step scan — the centerpiece */}
          {!accepted ? (
            <Card>
              <CardHeader className="pb-3">
                <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                  <IconScan className="h-5 w-5" aria-hidden="true" />
                  スキャン照合（ロケーション → 商品）
                </CardTitle>
                <CardDescription>
                  ① 棚のロケーションバーコードをスキャンして棚を確認 → ② 商品の JAN/SKU
                  をスキャンすると、その明細のピッキング数量が 1 点ずつ加算されます。
                </CardDescription>
              </CardHeader>
              <CardContent className="flex flex-col gap-4">
                {/* current-location pointer */}
                {current ? (
                  <div className="flex flex-wrap items-center justify-between gap-2 rounded-lg border bg-muted/30 p-3">
                    <div className="flex items-center gap-2">
                      <IconRoute className="h-4 w-4 text-primary" aria-hidden="true" />
                      <span className="text-sm text-muted-foreground">次のロケーション</span>
                      <span className="font-mono text-base font-semibold tabular-nums">
                        {current.location}
                      </span>
                    </div>
                    <span className="text-sm">
                      <span className="font-medium">{current.name}</span>
                      <span className="ml-2 text-muted-foreground tabular-nums">
                        {current.picked} / {current.instructed} 点
                      </span>
                    </span>
                  </div>
                ) : null}

                {/* stage stepper */}
                <ol className="flex items-center gap-2 text-sm" aria-label="スキャン手順">
                  <li
                    className={
                      scanStage === "location"
                        ? "flex items-center gap-1.5 font-semibold text-primary"
                        : "flex items-center gap-1.5 text-success-strong"
                    }
                  >
                    {confirmedLocation ? (
                      <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                    ) : (
                      <IconCircleDot className="h-4 w-4" aria-hidden="true" />
                    )}
                    ① ロケーション
                  </li>
                  <IconArrowRight className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
                  <li
                    className={
                      scanStage === "item"
                        ? "flex items-center gap-1.5 font-semibold text-primary"
                        : "flex items-center gap-1.5 text-muted-foreground"
                    }
                  >
                    <IconCircleDot className="h-4 w-4" aria-hidden="true" />② 商品
                  </li>
                </ol>

                {/* STEP 1 — location scan */}
                {scanStage === "location" ? (
                  <ScanInput
                    key={`loc-${current?.id ?? "none"}`}
                    label="① ロケーションをスキャン"
                    description={
                      current
                        ? `棚 ${current.location} のバーコードをスキャン（または入力して Enter）。`
                        : "ピッキング対象がありません。"
                    }
                    placeholder="棚番ラベルをスキャン…（例 LOC-A-03-01）"
                    icon={<IconMapPin className="h-4 w-4" aria-hidden="true" />}
                    inputMode="text"
                    onScan={handleLocationScan}
                    disabled={!current}
                    autoFocus
                  />
                ) : (
                  /* STEP 2 — item scan (only after location confirmed) */
                  <div className="flex flex-col gap-2">
                    <Alert variant="success">
                      <IconMapPin className="h-4 w-4" aria-hidden="true" />
                      <AlertTitle as="h3">
                        ロケーション {confirmedLocation} を確認済み
                      </AlertTitle>
                      <AlertDescription>
                        この棚の商品をスキャンしてください。別の棚へ移る場合は「次のロケーションへ」。
                      </AlertDescription>
                    </Alert>
                    <ScanInput
                      key={`item-${confirmedLocation}`}
                      label="② 商品をスキャン"
                      description="商品の JAN / SKU をスキャン（または入力して Enter）すると 1 点加算されます。"
                      placeholder="商品をスキャン…（例 4901234500011）"
                      inputMode="numeric"
                      onScan={handleItemScan}
                      autoFocus
                    />
                    <Button
                      variant="outline"
                      size="sm"
                      className="self-start"
                      onClick={() => {
                        setScanStage("location");
                        setConfirmedLocation(null);
                      }}
                    >
                      <IconBarcode className="h-4 w-4" aria-hidden="true" />
                      ロケーションを再スキャン
                    </Button>
                  </div>
                )}

                {/* recent scan feed */}
                {feed.length ? (
                  <div className="flex flex-col gap-1.5">
                    <p className="text-xs font-medium text-muted-foreground">最近のスキャン</p>
                    <ul className="flex flex-col gap-1">
                      {feed.map((f) => (
                        <li
                          key={f.id}
                          className="flex items-center justify-between gap-2 rounded-md border bg-muted/30 px-2.5 py-1.5 text-xs"
                        >
                          <span className="flex items-center gap-2 truncate">
                            <Badge
                              variant={
                                f.kind === "ok" ? "success" : f.kind === "warn" ? "warning" : "destructive"
                              }
                            >
                              {f.kind === "ok" ? "OK" : f.kind === "warn" ? "注意" : "対象外"}
                            </Badge>
                            <span className="truncate font-medium">{f.label}</span>
                          </span>
                          <span className="shrink-0 font-mono tabular-nums text-muted-foreground">
                            {f.detail}
                          </span>
                        </li>
                      ))}
                    </ul>
                  </div>
                ) : null}
              </CardContent>
            </Card>
          ) : null}

          {/* pick-lines grid */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <IconClipboardCheck className="h-5 w-5" aria-hidden="true" />
                ピッキングリスト
              </CardTitle>
              <CardDescription>
                ロケーション順（ピッキング動線）。スキャンでピッキング済が加算され、残数が自動計算されます。
                在庫が足りない行は「欠品にする」を選び、欠品理由を記録します。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <EditableDataTable
                columns={columns}
                rows={lines}
                getRowId={(l) => l.id}
                rowLabel={(i) => lines[i]?.name ?? `行 ${i + 1}`}
                getRowError={showErrors ? (row) => problemByLine.get(row.id) : undefined}
                renderFooterCell={footerCell}
                caption="ピッキングリスト — スキャンでピッキング済が加算され、残数・状態が自動更新されます。"
              />
            </CardContent>
          </Card>

          {/* short-pick gate — revealed when any line is short-marked without a reason */}
          <RevealSection open={!accepted && shortCount > 0} label="欠品処理">
            <Alert variant="warning">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">欠品処理が必要です（{shortCount} 件）</AlertTitle>
              <AlertDescription>
                欠品にした行には「欠品理由」（在庫切れ / 棚違い / 破損 / ロケーション不明）が必要です。
                理由を選択するまでピッキング完了はできません。
              </AlertDescription>
            </Alert>
          </RevealSection>

          {/* validation summary on complete attempt */}
          <RevealSection open={showErrors && problems.length > 0} label="ピッキング完了エラー">
            <Alert variant="destructive">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">ピッキングを完了できません（{problems.length} 件）</AlertTitle>
              <AlertDescription>
                <ul className="ml-4 list-disc">
                  {problems.map((p) => (
                    <li key={`${p.lineId}-${p.message}`}>{p.message}</li>
                  ))}
                </ul>
              </AlertDescription>
            </Alert>
          </RevealSection>

          {/* completion confirmation */}
          {accepted ? (
            <Alert variant="success">
              <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">ピッキング完了</AlertTitle>
              <AlertDescription>
                {order.orderNumber}（{order.shipTo}）のピッキングを完了しました。ピッキング{" "}
                {formatNumber(picked)} 点 · 欠品 {formatNumber(shortCount)} 件 · 金額 {yen(pickedValue)}
                。梱包・出荷へ引き渡せます。
              </AlertDescription>
            </Alert>
          ) : null}

          {/* actions */}
          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
            <div className="text-xs text-muted-foreground" aria-live="polite">
              {accepted
                ? "このピッキングは完了済みです（読み取り専用）。"
                : savedAt
                  ? `一時保存しました（${savedAt}）。`
                  : `ピッキング ${formatNumber(picked)} / ${formatNumber(instructed)} 点 · 完了 ${completeLines}/${lines.length} 行 · 欠品 ${shortCount} 件`}
            </div>
            <div className="flex flex-wrap items-center gap-2">
              {accepted ? (
                <>
                  <Button variant="outline" onClick={() => setSummaryOpen(true)}>
                    <IconClipboardList className="h-4 w-4" aria-hidden="true" />
                    ピッキング結果
                  </Button>
                  <Button variant="secondary" onClick={reset}>
                    新しいオーダーをピッキング
                  </Button>
                </>
              ) : (
                <>
                  <Button
                    variant="ghost"
                    onClick={() => {
                      setSavedAt(
                        new Date().toLocaleTimeString("ja-JP", {
                          hour: "2-digit",
                          minute: "2-digit",
                        }),
                      );
                    }}
                  >
                    <IconDeviceFloppy className="h-4 w-4" aria-hidden="true" />
                    一時保存
                  </Button>
                  <Button variant="outline" onClick={goToNext} disabled={settledLines >= lines.length}>
                    <IconArrowBigRightLines className="h-4 w-4" aria-hidden="true" />
                    次のロケーションへ
                  </Button>
                  <Button variant="outline" onClick={() => setSummaryOpen(true)}>
                    <IconClipboardList className="h-4 w-4" aria-hidden="true" />
                    結果サマリ
                  </Button>
                  <Button variant="success" onClick={attemptComplete} disabled={picked === 0 && shortCount === 0}>
                    <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                    ピッキング完了
                  </Button>
                </>
              )}
            </div>
          </div>

          {/* handoff CTA after completion */}
          {accepted ? (
            <div className="flex justify-end">
              <Button variant="primary" onClick={() => setSummaryOpen(true)}>
                <IconPackageExport className="h-4 w-4" aria-hidden="true" />
                出荷へ引き渡し
              </Button>
            </div>
          ) : null}
        </>
      ) : null}

      {/* result / handoff summary */}
      <Dialog open={summaryOpen} onOpenChange={setSummaryOpen}>
        <DialogContent className="max-h-[85vh] overflow-y-auto sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>ピッキング結果サマリ — {order?.orderNumber}</DialogTitle>
            <DialogDescription>
              {order?.shipTo} · 出荷予定 {order?.shipDate} · {order?.warehouse}
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-3 text-sm">
            <ul className="flex flex-col divide-y">
              {lines.map((l) => {
                const s = lineState(l);
                return (
                  <li key={l.id} className="flex items-center justify-between gap-3 py-2">
                    <span className="flex flex-col">
                      <span className="font-medium">{l.name}</span>
                      <span className="font-mono text-xs text-muted-foreground tabular-nums">
                        {l.location} · ピッキング {l.picked} / 指示 {l.instructed}
                      </span>
                    </span>
                    <span className="flex shrink-0 items-center gap-2">
                      <Badge variant={STATE_BADGE_VARIANT[s]} className="gap-1">
                        {STATE_ICON[s]}
                        {LINE_STATE_LABEL[s]}
                      </Badge>
                    </span>
                  </li>
                );
              })}
            </ul>
            <Separator />
            <dl className="flex flex-col gap-1.5">
              <div className="flex justify-between">
                <dt className="text-muted-foreground">指示合計</dt>
                <dd className="tabular-nums">{formatNumber(instructed)} 点</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">ピッキング合計</dt>
                <dd className="tabular-nums">{formatNumber(picked)} 点</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">欠品件数</dt>
                <dd className="tabular-nums">{formatNumber(shortCount)} 件</dd>
              </div>
              <div className="flex justify-between font-semibold">
                <dt>ピッキング金額</dt>
                <dd className="tabular-nums">{yen(pickedValue)}</dd>
              </div>
            </dl>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setSummaryOpen(false)}>
              <IconX className="h-4 w-4" aria-hidden="true" />
              閉じる
            </Button>
            {accepted ? (
              <Button variant="primary" onClick={() => setSummaryOpen(false)}>
                <IconPackageExport className="h-4 w-4" aria-hidden="true" />
                梱包へ引き渡し
              </Button>
            ) : null}
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}
